const loginGatePage=`<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>LOGIN | BARE.</title>${loginGateStyle}</head><body><main class="login-shell"><nav class="login-top" aria-label="구매 로그인 이동"><button class="login-icon back-button" type="button" aria-label="이전으로"><svg viewBox="0 0 24 24"><path d="M15 18 9 12l6-6"/></svg></button><span></span><a class="login-icon home-link" href="/" aria-label="홈으로"><svg viewBox="0 0 24 24"><path d="m3 11 9-8 9 8"/><path d="M5 10v10h14V10"/><path d="M9 20v-6h6v6"/></svg></a></nav><div class="brand-mark"><img src="${logoUrl}" alt="BARE."></div><section aria-labelledby="login-title"><h1 id="login-title">로그인</h1><p class="intro">아이디와 비밀번호 입력하기 귀찮으시죠?<br>1초 회원가입으로 입력없이 간편하게 로그인 하세요.</p><button class="kakao-login social-login" type="button"><svg viewBox="0 0 24 24" aria-hidden="true"><path d="M12 4C6.49 4 2 7.54 2 11.9c0 2.83 1.9 5.3 4.75 6.7l-.82 3.02c-.12.45.38.82.77.56l3.58-2.38c.56.07 1.13.1 1.72.1 5.51 0 10-3.54 10-7.9S17.51 4 12 4Z"/></svg><span>카카오 1초 로그인/회원가입</span></button><p class="benefit-copy">카카오 1초 회원가입 시 베어닷 채널 추가 및<br>광고성 마케팅 수신 동의 고객에 한하여 혜택이 제공됩니다.</p><div class="benefits" aria-label="회원가입 혜택"><div class="benefit-card"><div class="benefit-num">01</div><div class="benefit-main">5,000원<br>쿠폰 증정</div></div><div class="benefit-card"><div class="benefit-num">02</div><div class="benefit-main">인기제품 7종<br>50% 할인</div><div class="benefit-sub">*7종 택1</div></div><div class="benefit-card"><div class="benefit-num">03</div><div class="benefit-main">금액대별<br>할인 쿠폰</div><div class="benefit-sub">*5만원 / 7만원 / 10만원</div></div></div><div class="divider">또는</div><div class="member-switch" role="tablist"><button class="is-active" type="button">기존 회원이세요?</button><button type="button">비회원 배송조회</button></div><form class="login-form"><label class="login-field"><input type="email" name="email" autocomplete="email" placeholder="이메일"></label><label class="login-field"><input type="password" name="password" autocomplete="current-password" placeholder="비밀번호"></label><button class="member-login" type="submit">기존 회원 로그인</button><button class="guest-buy" type="button">비회원 구매</button></form><div class="login-links"><div><button type="button" class="soft-action">아이디 찾기</button><span>|</span><button type="button" class="soft-action">비밀번호 찾기</button></div><button type="button" class="soft-action">회원가입</button></div><div class="divider">또는</div><button class="naver-login social-login" type="button" aria-label="네이버 로그인">N</button><p class="signup-copy">첫 구매가 빨라지는 <strong>1초 회원가입</strong> <span aria-hidden="true">⚡</span><br>살까 말까 고민하던 고객까지 막힘없이<small>i</small></p><p class="muted-copy">BARE.도 이미 1초 회원가입 사용 중</p></section></main><script>const checkoutUrl='/order/orderform.html?basket_type=A0000&delvtype=A';const params=new URLSearchParams(location.search);const returnUrl=params.get('returnUrl')||checkoutUrl;const readyMessage='카카오/네이버/회원 로그인은 실제 간편 로그인 키 연동 후 사용할 수 있어요. 지금은 비회원 구매로 결제까지 진행할 수 있습니다.';document.querySelector('.back-button')?.addEventListener('click',()=>{if(history.length>1)history.back();else location.href='/'});document.querySelector('.guest-buy')?.addEventListener('click',()=>{location.href=returnUrl});document.querySelector('.login-form')?.addEventListener('submit',event=>{event.preventDefault();alert(readyMessage)});document.querySelectorAll('.social-login,.soft-action,.member-switch button').forEach(btn=>btn.addEventListener('click',()=>{if(!btn.classList.contains('guest-buy'))alert(readyMessage)}));</script></body></html>`;
const checkoutPage=`<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>ORDER | BARE.</title>${checkoutStyle}</head><body><header class="checkout-top"><a href="/"><img src="${logoUrl}" alt="BARE."></a></header><main class="checkout"><h1>ORDER FORM</h1><form class="checkout-grid" id="checkout-form"><section><div class="panel"><h2>배송지</h2><div class="tabs"><span>최근 배송지</span><span>직접입력</span></div><div class="row"><div class="field"><label for="buyer">주문자명</label><input id="buyer" name="buyer" autocomplete="name" required></div><div class="field"><label for="phone">연락처</label><input id="phone" name="phone" autocomplete="tel" required></div></div><div class="field"><label for="address">주소</label><input id="address" name="address" autocomplete="street-address" required></div><div class="field"><label for="memo">배송 메모</label><textarea id="memo" name="memo" placeholder="배송 요청사항을 입력해주세요"></textarea></div></div><div class="panel"><h2>할인/부가결제</h2><div class="summary-line"><span>자동 할인</span><strong>₩0</strong></div><div class="summary-line"><span>쿠폰 할인</span><strong>₩0</strong></div></div></section><aside><div class="panel"><h2>주문상품</h2><div class="order-list" id="order-list"></div></div><div class="panel"><h2>최종 결제 금액</h2><div class="summary-line"><span>주문상품</span><strong id="subtotal">₩0</strong></div><div class="summary-line"><span>배송비</span><strong id="shipping">₩3,500</strong></div><div class="summary-line total"><span>최종 결제금액</span><strong id="grand-total">₩0</strong></div></div><div class="panel"><h2>결제수단</h2><div class="payment-methods" role="radiogroup" aria-label="결제수단 선택"><label class="pay-option"><input type="radio" name="payMethod" value="CARD" checked> 카드/간편결제</label><label class="pay-option"><input type="radio" name="payMethod" value="TRANSFER"> 퀵계좌이체</label></div><p class="payment-window-note">선택한 결제수단에 맞춰 토스페이먼츠 결제창으로 이동합니다.</p><label class="agree"><input type="checkbox" required> 결제조건과 개인정보 수집 및 이용에 동의합니다.</label><button class="checkout-submit" type="submit">결제하기</button><p class="notice" id="checkout-notice">토스페이먼츠 테스트 결제창으로 결제를 진행합니다. 테스트 결제는 실제 출금되지 않습니다.</p></div></aside></form></main><script src="https://js.tosspayments.com/v2/standard"></script><script>const tossClientKey='${tossClientKey}';const money=value=>'₩'+Number(value||0).toLocaleString('ko-KR');const read=key=>{try{return JSON.parse(localStorage.getItem(key)||'[]')}catch{return[]}};const write=(key,value)=>localStorage.setItem(key,JSON.stringify(value));const items=read('bare_checkout_items').length?read('bare_checkout_items'):read('bare_cart_items');const list=document.getElementById('order-list');const subtotal=items.reduce((sum,item)=>sum+Number(item.price||0),0);const shipping=items.length?3500:0;const grandTotal=subtotal+shipping;const submit=document.querySelector('.checkout-submit');const notice=document.getElementById('checkout-notice');if(!items.length){list.innerHTML='<p class="empty">주문할 상품이 없습니다.<br><a href="/">상품을 먼저 선택해주세요.</a></p>';submit.disabled=true}else{list.innerHTML=items.map(item=>'<article class="order-item"><img src="'+(item.image||'')+'" alt=""><div><p class="order-title">'+(item.title||'BARE. product')+'</p><p class="order-meta">'+(item.option||'옵션 선택 내역 없음')+'</p></div><strong class="price">'+money(item.price)+'</strong></article>').join('')}document.getElementById('subtotal').textContent=money(subtotal);document.getElementById('shipping').textContent=money(shipping);document.getElementById('grand-total').textContent=money(grandTotal);const customerKey=localStorage.getItem('bare_toss_customer_key')||('BARE_'+Date.now()+'_'+Math.random().toString(36).slice(2,10));localStorage.setItem('bare_toss_customer_key',customerKey);const tossPayments=TossPayments(tossClientKey);const payment=tossPayments.payment({customerKey});document.getElementById('checkout-form').addEventListener('submit',async event=>{event.preventDefault();if(!items.length)return;if(!event.currentTarget.reportValidity())return;const buyer=document.getElementById('buyer').value.trim();const phone=document.getElementById('phone').value.replace(/[^0-9]/g,'');const address=document.getElementById('address').value.trim();const memo=document.getElementById('memo').value.trim();const orderId='BARE-'+Date.now()+'-'+Math.random().toString(36).slice(2,8).toUpperCase();const orderName=items.length>1?(items[0].title||'BARE. product')+' 외 '+(items.length-1)+'건':(items[0].title||'BARE. product');write('bare_pending_order',{orderId,items,amount:grandTotal,buyer,phone,address,memo,createdAt:Date.now()});write('bare_checkout_items',items);submit.disabled=true;notice.textContent='토스페이먼츠 결제창을 여는 중입니다.';const method=document.querySelector('input[name="payMethod"]:checked')?.value||'CARD';try{await payment.requestPayment({method,amount:{currency:'KRW',value:grandTotal},orderId,orderName,successUrl:location.origin+'/order/success',failUrl:location.origin+'/order/fail',customerName:buyer,customerMobilePhone:phone})}catch(error){submit.disabled=false;notice.textContent='토스페이먼츠 테스트 결제창으로 결제를 진행합니다. 테스트 결제는 실제 출금되지 않습니다.';if(error?.code==='USER_CANCEL')return;alert(error?.message||'결제를 시작하지 못했습니다.')}});</script></body></html>`;
const tossResultStyle=`<style>@font-face{font-family:InterDisplay;src:url(https://framerusercontent.com/assets/qITWJ2WdG0wrgQPDb8lvnYnTXDg.woff2) format('woff2');font-weight:700;font-display:swap}*{box-sizing:border-box}body{margin:0;background:#050505;color:#fff;font-family:InterDisplay,Pretendard,'Noto Sans KR',system-ui,sans-serif}.checkout-top{height:76px;display:grid;place-items:center;background:#fff}.checkout-top img{width:70px;filter:brightness(0)}.result{width:min(620px,calc(100% - 36px));margin:0 auto;padding:90px 0 120px}.result h1{margin:0 0 16px;font-size:24px}.result p{margin:0 0 18px;color:#d8d8d8;font:800 13px/1.65 Pretendard,'Noto Sans KR',sans-serif}.result-box{display:grid;gap:10px;margin:22px 0;padding:18px;border-top:1px solid #444;border-bottom:1px solid #333}.result-line{display:flex;justify-content:space-between;gap:16px;color:#eee;font-size:12px}.result-actions{display:flex;flex-wrap:wrap;gap:8px;margin-top:24px}.result-actions a{display:inline-flex;align-items:center;justify-content:center;min-height:44px;padding:0 16px;background:#fff;color:#050505;text-decoration:none;font:900 12px/1 InterDisplay,Pretendard,sans-serif}.result-actions a.secondary{border:1px solid #444;background:#050505;color:#fff}.result-status{color:#aaa}@media(max-width:640px){.result{padding:58px 0 90px}.result-line{display:grid}}</style>`;
const tossSuccessPage=`<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>PAYMENT SUCCESS | BARE.</title>${tossResultStyle}</head><body><header class="checkout-top"><a href="/"><img src="${logoUrl}" alt="BARE."></a></header><main class="result"><h1>결제 확인 중</h1><p class="result-status" id="result-status">토스페이먼츠 승인 결과를 확인하고 있습니다.</p><div class="result-box" id="result-box"></div><div class="result-actions"><a href="/">SHOP으로 돌아가기</a><a class="secondary" href="/order/orderform.html?basket_type=A0000&delvtype=A">주문서로 돌아가기</a></div></main><script>const money=value=>'₩'+Number(value||0).toLocaleString('ko-KR');const read=key=>{try{return JSON.parse(localStorage.getItem(key)||'[]')}catch{return[]}};const write=(key,value)=>localStorage.setItem(key,JSON.stringify(value));const params=new URLSearchParams(location.search);const paymentKey=params.get('paymentKey'),orderId=params.get('orderId'),amount=Number(params.get('amount')||0);const statusEl=document.getElementById('result-status'),box=document.getElementById('result-box');function draw(title,lines){document.querySelector('.result h1').textContent=title;box.innerHTML=lines.map(([label,value])=>'<div class="result-line"><span>'+label+'</span><strong>'+value+'</strong></div>').join('')}async function confirmPayment(){if(!paymentKey||!orderId||!amount){statusEl.textContent='결제 승인에 필요한 정보가 부족합니다.';draw('결제 확인 실패',[['주문번호',orderId||'-'],['결제금액',amount?money(amount):'-']]);return}const pending=read('bare_pending_order');if(!pending||pending.orderId!==orderId||Number(pending.amount)!==amount){statusEl.textContent='주문 정보와 결제 금액이 일치하지 않아 승인을 중단했습니다.';draw('결제 확인 실패',[['주문번호',orderId],['결제금액',money(amount)]]);return}try{const response=await fetch('/api/toss/confirm',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({paymentKey,orderId,amount,order:pending})});const data=await response.json();if(!response.ok)throw new Error(data.message||'결제 승인에 실패했습니다.');const orders=read('bare_order_items');const next=(pending.items||[]).map(item=>({...item,status:'결제 완료',paymentKey,orderId,createdAt:Date.now()}));write('bare_order_items',[...next,...orders].slice(0,30));localStorage.removeItem('bare_pending_order');localStorage.removeItem('bare_checkout_items');statusEl.textContent='결제가 정상적으로 승인되었습니다.';draw('결제 완료',[['주문번호',data.orderId||orderId],['결제금액',money(data.totalAmount||amount)],['결제수단',data.method||'-']])}catch(error){statusEl.textContent=error.message;draw('결제 승인 실패',[['주문번호',orderId],['결제금액',money(amount)]])}}confirmPayment();</script></body></html>`;
const tossFailPage=`<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>PAYMENT FAIL | BARE.</title>${tossResultStyle}</head><body><header class="checkout-top"><a href="/"><img src="${logoUrl}" alt="BARE."></a></header><main class="result"><h1>결제 실패</h1><p id="fail-message">결제가 완료되지 않았습니다.</p><div class="result-box" id="result-box"></div><div class="result-actions"><a href="/order/orderform.html?basket_type=A0000&delvtype=A">다시 결제하기</a><a class="secondary" href="/">SHOP으로 돌아가기</a></div></main><script>const params=new URLSearchParams(location.search);document.getElementById('fail-message').textContent=params.get('message')||'결제가 취소되었거나 실패했습니다.';document.getElementById('result-box').innerHTML='<div class="result-line"><span>에러코드</span><strong>'+(params.get('code')||'-')+'</strong></div><div class="result-line"><span>주문번호</span><strong>'+(params.get('orderId')||'-')+'</strong></div>';</script></body></html>`;
function modernCheckoutPage(){return `<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>ORDER | BARE.</title><style>@font-face{font-family:InterDisplay;src:url(https://framerusercontent.com/assets/qITWJ2WdG0wrgQPDb8lvnYnTXDg.woff2) format('woff2');font-weight:700;font-display:swap}*{box-sizing:border-box}body{margin:0;background:#f0f0f0;color:#151515;font-family:InterDisplay,"Apple SD Gothic Neo",Pretendard,"Noto Sans KR",system-ui,sans-serif}.order-page{width:min(1180px,calc(100% - 34px));margin:0 auto;padding:8px 0 90px}.order-layout{display:grid;grid-template-columns:minmax(0,720px) 300px;gap:26px;align-items:start}.order-main{display:grid;gap:18px}.order-card,.pay-card{background:#fff;border-radius:14px;overflow:hidden}.card-head{display:flex;align-items:center;justify-content:space-between;min-height:56px;padding:0 20px;border-bottom:1px solid #e3e3e3;font:900 15px/1 Pretendard,"Noto Sans KR",sans-serif}.chev{font-size:18px}.product-list{display:grid;gap:0;padding:18px 20px}.product-item{display:grid;grid-template-columns:76px minmax(0,1fr) auto;gap:16px;align-items:start}.product-item img{width:76px;height:76px;object-fit:cover;background:#eee;border-radius:4px}.product-title{margin:0 0 9px;font:900 15px/1.25 Arial,"Apple SD Gothic Neo",sans-serif}.product-option{margin:0;color:#777;font:800 13px/1.35 Pretendard,sans-serif}.product-price{font:900 15px/1 InterDisplay,Pretendard,sans-serif;white-space:nowrap}.product-remove{border:0;background:transparent;font-size:24px;line-height:1;cursor:pointer}.ship-line{display:flex;justify-content:space-between;margin:16px 0 0;padding:16px;background:#fafafa;font:900 14px/1 Pretendard,sans-serif}.tabs{display:grid;grid-template-columns:1fr 1fr;margin:0 18px 18px}.tabs button{height:52px;border:0;border-bottom:4px solid transparent;background:#fff;color:#777;font:900 15px/1 Pretendard,sans-serif;cursor:pointer}.tabs button.is-active{border-color:#1557ff;color:#1557ff}.order-form{padding:0 20px 20px}.check-row{display:flex;align-items:center;gap:9px;margin:0 0 20px;font:800 13px/1 Pretendard,sans-serif}.check-row input{width:18px;height:18px;accent-color:#1557ff}.field{display:grid;gap:8px;margin:0 0 14px}.field label{font:900 13px/1 Pretendard,sans-serif}.field label span{color:#1557ff}.field input,.field select,.field textarea{width:100%;height:38px;border:1px solid #bbb;border-radius:2px;background:#fff;padding:0 12px;color:#151515;font:800 13px/1 Pretendard,sans-serif}.field textarea{height:88px;padding-top:10px;resize:vertical}.address-row{display:grid;grid-template-columns:minmax(0,1fr) 88px;gap:8px}.address-row button,.small-btn{height:38px;border:1px solid #999;background:#fff;color:#151515;font:900 12px/1 Pretendard,sans-serif;cursor:pointer}.email-row{display:grid;grid-template-columns:minmax(0,1fr) 22px minmax(120px,.8fr);gap:8px;align-items:center}.email-row span{text-align:center;color:#555;font-weight:900}.section-body{padding:18px 20px}.line{display:flex;justify-content:space-between;gap:14px;padding:10px 0;font:800 14px/1 Pretendard,sans-serif}.line.strong{font-weight:900}.discount{color:#e1002a}.coupon-row{display:grid;grid-template-columns:minmax(0,1fr) 88px;gap:8px;margin:10px 0}.pay-options{display:grid;gap:14px;padding:18px 20px}.pay-option{display:grid;gap:10px}.pay-option>label{display:flex;align-items:center;gap:10px;font:900 14px/1 Pretendard,sans-serif}.pay-option input{accent-color:#1557ff}.bank-fields{display:grid;gap:10px;margin-left:28px;padding-left:20px;border-left:4px solid #f2f2f2}.muted{color:#777;font:800 12px/1.45 Pretendard,sans-serif}.pay-card{position:sticky;top:18px;padding-bottom:18px}.pay-card .summary{padding:18px 20px}.pay-total{display:flex;justify-content:space-between;gap:14px;padding:18px 0;border-top:1px solid #ddd;font:900 18px/1 Pretendard,sans-serif}.benefit{display:flex;justify-content:space-between;padding:16px 20px;border-top:1px solid #eee;font:900 18px/1 Pretendard,sans-serif}.agree-box{padding:12px 20px 0;color:#555;text-align:center;font:800 12px/1.5 Pretendard,sans-serif}.checkout-submit{width:calc(100% - 40px);height:58px;margin:16px 20px 0;border:0;border-radius:4px;background:#1557ff;color:#fff;font:900 15px/1 Pretendard,sans-serif;cursor:pointer}.checkout-submit:disabled{opacity:.55;cursor:not-allowed}.notice{margin:12px 20px 0;color:#777;font:800 11px/1.5 Pretendard,sans-serif}.postcode-modal{position:fixed;inset:0;z-index:200;display:none;background:rgba(0,0,0,.35)}.postcode-modal.is-open{display:grid;place-items:center}.postcode-panel{position:relative;width:min(640px,calc(100% - 30px));height:min(760px,calc(100svh - 40px));background:#fff;box-shadow:0 20px 70px rgba(0,0,0,.22)}.postcode-head{display:flex;align-items:center;justify-content:space-between;height:68px;padding:0 20px;border-bottom:1px solid #eee}.postcode-head h2{margin:0;font:900 26px/1 Pretendard,sans-serif}.postcode-close{width:46px;height:46px;border:0;background:#fff;color:#555;font-size:36px;line-height:1;cursor:pointer}.postcode-frame{height:calc(100% - 68px)}@media(max-width:980px){.order-layout{grid-template-columns:1fr}.pay-card{position:static}}@media(max-width:640px){.order-page{width:100%;padding:0 0 70px}.order-card,.pay-card{border-radius:0}.product-item{grid-template-columns:62px minmax(0,1fr) auto}.product-item img{width:62px;height:62px}.email-row{grid-template-columns:1fr}.email-row span{text-align:left}.address-row{grid-template-columns:1fr}.order-layout{gap:12px}.postcode-panel{width:100%;height:100svh}.postcode-head h2{font-size:24px}}</style></head><body><main class="order-page"><form id="checkout-form" class="order-layout"><div class="order-main"><section class="order-card"><div class="card-head"><span>구매상품</span><span class="chev">⌃</span></div><div class="product-list" id="order-list"></div></section><section class="order-card"><div class="card-head"><span>배송지</span><span class="chev">⌃</span></div><div class="tabs"><button type="button">최근 배송지</button><button type="button" class="is-active">직접입력</button></div><div class="order-form"><label class="check-row"><input type="checkbox" id="same-member" checked> 회원 정보와 동일</label><div class="field"><label for="buyer">받는사람<span>*</span></label><input id="buyer" name="buyer" required></div><div class="field"><label>주소<span>*</span></label><div class="address-row"><input id="postcode" placeholder="우편번호" readonly required><button type="button" id="address-search">주소검색</button></div><input id="address" placeholder="주소" readonly required><input id="address-detail" placeholder="상세주소" required></div><div class="field"><label for="phone">휴대전화<span>*</span></label><input id="phone" name="phone" autocomplete="tel" placeholder="010-0000-0000" required></div><div class="field"><label>이메일<span>*</span></label><div class="email-row"><input id="email-id" placeholder="email" required><span>@</span><select id="email-domain"><option>kakao.com</option><option>naver.com</option><option>gmail.com</option><option>hanmail.net</option><option>직접입력</option></select></div></div><div class="field"><label for="memo-select">배송 요청사항</label><select id="memo-select"><option value="">-- 메시지 선택 (선택사항) --</option><option>문 앞에 놓아주세요.</option><option>배송 전 연락주세요.</option><option>부재 시 경비실에 맡겨주세요.</option></select></div><label class="check-row"><input type="checkbox"> 기본 배송지로 저장</label></div></section><section class="order-card"><div class="card-head"><span>할인/부가결제</span><span class="chev">⌃</span></div><div class="section-body"><div class="line"><span>자동 할인</span><strong class="discount" id="discount-line">-₩0</strong></div><div class="coupon-row"><input id="coupon-code" placeholder="할인코드 적용"><button class="small-btn" type="button">코드 적용</button></div><div class="coupon-row"><input value="₩0" readonly><button class="small-btn" type="button">쿠폰 적용</button></div><div class="line strong"><span>적용금액</span><strong class="discount" id="discount-total">-₩0</strong></div></div></section><section class="order-card"><div class="card-head"><span>추가입력</span><span class="chev">⌃</span></div><div class="section-body"><div class="field"><label for="extra">기타 문의사항</label><textarea id="extra"></textarea><p class="muted">Q&A에 자동 저장됩니다.</p></div><div class="field"><label for="order-pass">비밀번호</label><input id="order-pass" type="password"></div></div></section><section class="order-card"><div class="card-head"><span>결제수단</span><span class="chev">⌃</span></div><div class="pay-options"><div class="pay-option"><label><input type="radio" name="payMethod" value="TRANSFER" checked> 무통장입금</label><div class="bank-fields"><div class="field"><label>입금은행<span>*</span></label><select><option>:: 선택해 주세요. ::</option><option>국민은행</option><option>신한은행</option><option>우리은행</option></select></div><div class="field"><label>입금자명<span>*</span></label><input id="depositor"></div><div class="field"><label>현금영수증</label><label class="check-row"><input type="radio" name="cashReceipt"> 현금영수증 신청 <input type="radio" name="cashReceipt" checked> 신청안함</label></div></div></div><label class="pay-option"><span><input type="radio" name="payMethod" value="CARD"> 신용카드</span></label><label class="pay-option"><span><input type="radio" name="payMethod" value="KAKAOPAY"> 카카오페이</span></label><label class="pay-option"><span><input type="radio" name="payMethod" value="NAVERPAY"> 네이버페이</span></label><label class="check-row"><input type="checkbox"> 결제수단과 입력정보를 다음에도 사용</label></div></section></div><aside class="pay-card"><div class="card-head"><span>결제정보</span></div><div class="summary"><div class="line"><span>구매상품</span><strong id="subtotal">₩0</strong></div><div class="line"><span>배송비</span><strong id="shipping">₩0</strong></div><div class="line"><span>할인/부가결제</span><strong class="discount" id="summary-discount">-₩0</strong></div><div class="pay-total"><span>최종 결제 금액</span><strong id="grand-total">₩0</strong></div></div><div class="benefit"><span>적립 혜택</span><strong id="points">₩0⌄</strong></div><p class="agree-box">주문 내용을 확인하였으며 약관에 동의합니다.</p><button class="checkout-submit" type="submit" id="pay-button">결제하기</button><p class="notice" id="checkout-notice">토스페이먼츠 테스트 결제창으로 결제를 진행합니다.</p><p class="agree-box"><label><input type="checkbox" required> 구매조건 확인 및 결제진행 동의</label></p></aside></form></main><aside class="postcode-modal" id="postcode-modal" aria-hidden="true"><div class="postcode-panel"><div class="postcode-head"><h2>우편번호 검색</h2><button class="postcode-close" type="button" aria-label="닫기">×</button></div><div class="postcode-frame" id="postcode-frame"></div></div></aside><script src="https://js.tosspayments.com/v2/standard"></script><script src="//t1.daumcdn.net/mapjsapi/bundle/postcode/prod/postcode.v2.js"></script><script>const tossClientKey='${tossClientKey}';const money=value=>'₩'+Number(value||0).toLocaleString('ko-KR');const read=key=>{try{return JSON.parse(localStorage.getItem(key)||'[]')}catch{return[]}};const write=(key,value)=>localStorage.setItem(key,JSON.stringify(value));const items=read('bare_checkout_items').length?read('bare_checkout_items'):read('bare_cart_items');const social=(()=>{try{return JSON.parse(localStorage.getItem('bare_social_user')||'{}')}catch{return{}}})();const list=document.getElementById('order-list'),submit=document.getElementById('pay-button'),notice=document.getElementById('checkout-notice');const subtotal=items.reduce((sum,item)=>sum+Number(item.price||0),0);const shipping=items.length?0:0;const discount=items.length?Math.round(subtotal*.03):0;const grandTotal=Math.max(0,subtotal+shipping-discount);const points=discount;if(!items.length){list.innerHTML='<p class="muted">주문할 상품이 없습니다. 상품을 먼저 선택해주세요.</p>';submit.disabled=true}else{list.innerHTML=items.map(item=>'<article class="product-item"><img src="'+(item.image||'')+'" alt=""><div><p class="product-title">'+(item.title||'BARE. product')+'</p><p class="product-option">'+(item.option||'옵션 선택 내역 없음')+'</p><p class="product-price">'+money(item.price)+'</p></div><button type="button" class="product-remove" aria-label="삭제">×</button></article>').join('')+'<div class="ship-line"><span>배송비</span><strong>'+money(shipping)+' (무료)</strong></div>'}document.getElementById('subtotal').textContent=money(subtotal);document.getElementById('shipping').textContent=money(shipping);document.getElementById('discount-line').textContent='-'+money(discount);document.getElementById('discount-total').textContent='-'+money(discount);document.getElementById('summary-discount').textContent='-'+money(discount);document.getElementById('grand-total').textContent=money(grandTotal);document.getElementById('points').textContent=money(points)+'⌄';submit.textContent=money(grandTotal)+' 결제하기';if(social.name)document.getElementById('buyer').value=social.name;if(social.email){const parts=social.email.split('@');document.getElementById('email-id').value=parts[0]||'';if(parts[1])document.getElementById('email-domain').value=parts[1]}const modal=document.getElementById('postcode-modal'),frame=document.getElementById('postcode-frame');function closePostcode(){modal.classList.remove('is-open');modal.setAttribute('aria-hidden','true');frame.innerHTML=''}function openPostcode(){modal.classList.add('is-open');modal.setAttribute('aria-hidden','false');frame.innerHTML='';if(!window.daum||!window.daum.Postcode){alert('우편번호 검색 스크립트를 불러오는 중입니다. 잠시 후 다시 눌러주세요.');return}new daum.Postcode({oncomplete:data=>{document.getElementById('postcode').value=data.zonecode||'';document.getElementById('address').value=data.roadAddress||data.jibunAddress||'';document.getElementById('address-detail').focus();closePostcode()},width:'100%',height:'100%'}).embed(frame)}document.getElementById('address-search').addEventListener('click',openPostcode);document.querySelector('.postcode-close').addEventListener('click',closePostcode);modal.addEventListener('click',event=>{if(event.target===modal)closePostcode()});document.addEventListener('keydown',event=>{if(event.key==='Escape')closePostcode()});const customerKey=localStorage.getItem('bare_toss_customer_key')||('BARE_'+Date.now()+'_'+Math.random().toString(36).slice(2,10));localStorage.setItem('bare_toss_customer_key',customerKey);const tossPayments=TossPayments(tossClientKey);const payment=tossPayments.payment({customerKey});document.getElementById('checkout-form').addEventListener('submit',async event=>{event.preventDefault();if(!items.length)return;if(!event.currentTarget.reportValidity())return;const buyer=document.getElementById('buyer').value.trim();const phone=document.getElementById('phone').value.replace(/[^0-9]/g,'');const address=[document.getElementById('postcode').value,document.getElementById('address').value,document.getElementById('address-detail').value].filter(Boolean).join(' ');const memo=[document.getElementById('memo-select').value,document.getElementById('extra').value].filter(Boolean).join(' / ');const orderId='BARE-'+Date.now()+'-'+Math.random().toString(36).slice(2,8).toUpperCase();const orderName=items.length>1?(items[0].title||'BARE. product')+' 외 '+(items.length-1)+'건':(items[0].title||'BARE. product');write('bare_pending_order',{orderId,items,amount:grandTotal,buyer,phone,address,memo,createdAt:Date.now()});write('bare_checkout_items',items);submit.disabled=true;notice.textContent='토스페이먼츠 결제창을 여는 중입니다.';const selected=document.querySelector('input[name="payMethod"]:checked')?.value||'CARD';let method=selected;const request={method,amount:{currency:'KRW',value:grandTotal},orderId,orderName,successUrl:location.origin+'/order/success',failUrl:location.origin+'/order/fail',customerName:buyer,customerMobilePhone:phone};if(selected==='KAKAOPAY'||selected==='NAVERPAY'){request.method='EASY_PAY';request.easyPay=selected==='KAKAOPAY'?'KAKAOPAY':'NAVERPAY'}try{await payment.requestPayment(request)}catch(error){submit.disabled=false;notice.textContent='토스페이먼츠 테스트 결제창으로 결제를 진행합니다.';if(error?.code==='USER_CANCEL')return;alert(error?.message||'결제를 시작하지 못했습니다.')}});</script></body></html>`}
function jsonResponse(data,status=200){return new Response(JSON.stringify(data),{status,headers:{'content-type':'application/json;charset=utf-8','cache-control':'no-cache'}})}
function supabaseConfigFromEnv(env){return{url:(env.SUPABASE_URL||'https://adltmckypuqwzbcuvuuh.supabase.co').replace(/\/$/,''),key:env.SUPABASE_SERVICE_ROLE_KEY||env.SUPABASE_SERVICE_KEY||env.SUPABASE_ANON_KEY||''}}
function normalizeOrderForSupabase(order,payment){const items=Array.isArray(order?.items)?order.items:[];return{order_id:payment.orderId,payment_key:payment.paymentKey,status:'paid',amount:Number(payment.totalAmount||payment.amount||order?.amount||0),method:payment.method||'',buyer_name:String(order?.buyer||payment.customerName||''),buyer_phone:String(order?.phone||''),shipping_address:String(order?.address||''),shipping_memo:String(order?.memo||''),items,raw_payment:payment,created_at:new Date().toISOString()}}
async function saveOrderToSupabase(env,order,payment){const cfg=supabaseConfigFromEnv(env);if(!cfg.key)return{saved:false,message:'SUPABASE_SERVICE_ROLE_KEY 또는 SUPABASE_ANON_KEY가 설정되지 않았습니다.'};const payload=normalizeOrderForSupabase(order,payment);for(const table of ['orders','bare_orders']){const response=await fetch(cfg.url+'/rest/v1/'+table,{method:'POST',headers:{apikey:cfg.key,Authorization:'Bearer '+cfg.key,'Content-Type':'application/json',Prefer:'return=representation'},body:JSON.stringify(payload)});if(response.ok)return{saved:true,table};const text=await response.text();if(response.status!==404)return{saved:false,table,message:text}}return{saved:false,message:'Supabase orders/bare_orders 테이블을 찾지 못했습니다.'}}
async function confirmTossPayment(request,env){if(request.method!=='POST')return jsonResponse({message:'Method not allowed'},405);const secretKey=env.TOSS_SECRET_KEY;if(!secretKey)return jsonResponse({message:'TOSS_SECRET_KEY가 설정되지 않았습니다.'},500);let payload;try{payload=await request.json()}catch{return jsonResponse({message:'요청 본문을 확인할 수 없습니다.'},400)}const paymentKey=payload.paymentKey,orderId=payload.orderId,amount=Number(payload.amount),order=payload.order||{};if(!paymentKey||!orderId||!amount)return jsonResponse({message:'paymentKey, orderId, amount가 필요합니다.'},400);const response=await fetch('https://api.tosspayments.com/v1/payments/confirm',{method:'POST',headers:{Authorization:'Basic '+btoa(secretKey+':'),'Content-Type':'application/json'},body:JSON.stringify({paymentKey,orderId,amount})});const result=await response.json().catch(async()=>({message:await response.text()}));if(!response.ok)return jsonResponse(result,response.status);const dbResult=await saveOrderToSupabase(env,order,{...result,paymentKey,orderId,amount});return jsonResponse({...result,dbSaved:dbResult.saved,dbTable:dbResult.table||null,dbMessage:dbResult.message||null},200)}
function simpleLoginPage(){return `<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>LOGIN | BARE.</title><style>@font-face{font-family:InterDisplay;src:url(https://framerusercontent.com/assets/qITWJ2WdG0wrgQPDb8lvnYnTXDg.woff2) format('woff2');font-weight:700;font-display:swap}*{box-sizing:border-box}body{margin:0;background:#fff;color:#202020;font-family:InterDisplay,"Apple SD Gothic Neo",Pretendard,"Noto Sans KR",system-ui,sans-serif}.login-wrap{width:min(760px,calc(100% - 40px));margin:0 auto;padding:70px 0 50px}.login-form{display:grid;gap:0}.login-field input{width:100%;height:86px;border:0;border-bottom:1px solid #e2e2e2;background:#fff;color:#202020;padding:0 2px;font:900 28px/1 Pretendard,"Noto Sans KR",sans-serif}.login-field input::placeholder{color:#999}.member-login,.guest-buy{width:100%;height:110px;margin-top:28px;border:2px solid #0068e6;border-radius:14px;background:#f7f8fa;color:#202020;font:900 36px/1 Pretendard,"Noto Sans KR",sans-serif;cursor:pointer}.guest-buy{margin-top:20px;border:1px solid #d8d8d8;background:#fff}.login-links{display:flex;align-items:center;justify-content:space-between;margin:34px 8px 66px;color:#8d8d8d;font:900 24px/1 Pretendard,"Noto Sans KR",sans-serif}.login-links button{border:0;background:transparent;color:inherit;font:inherit;cursor:pointer}.login-links span{padding:0 18px;color:#cfcfcf}.divider{display:flex;align-items:center;gap:22px;margin:0 0 42px;color:#c1c1c1;font:900 22px/1 Pretendard,"Noto Sans KR",sans-serif}.divider:before,.divider:after{content:"";height:1px;background:#eee;flex:1}.social-row{display:flex;align-items:center;justify-content:center;gap:18px}.social-login{display:grid;place-items:center;width:96px;height:96px;border:0;border-radius:50%;font:900 54px/1 Arial,sans-serif;cursor:pointer}.social-login.naver{background:#03c75a;color:#fff}.social-login.kakao{background:#fee500;color:#050505}.social-login.kakao svg{width:48px;height:48px;fill:#050505}@media(max-width:560px){.login-wrap{width:calc(100% - 36px);padding-top:54px}.login-field input{height:72px;font-size:26px}.member-login,.guest-buy{height:86px;font-size:30px}.login-links{font-size:20px;margin-bottom:52px}.divider{font-size:18px}.social-login{width:78px;height:78px;font-size:44px}.social-login.kakao svg{width:40px;height:40px}}</style></head><body><main class="login-wrap"><form class="login-form"><label class="login-field"><input type="email" name="email" autocomplete="email" placeholder="이메일"></label><label class="login-field"><input type="password" name="password" autocomplete="current-password" placeholder="비밀번호"></label><button class="member-login" type="submit">기존 회원 로그인</button><button class="guest-buy" type="button">비회원 구매</button></form><div class="login-links"><div><button type="button" class="soft-action">아이디 찾기</button><span>|</span><button type="button" class="soft-action">비밀번호 찾기</button></div><button type="button" class="soft-action">회원가입</button></div><div class="divider">또는</div><div class="social-row" aria-label="간편 로그인"><button class="social-login naver" type="button" aria-label="네이버 로그인">N</button><button class="social-login kakao" type="button" aria-label="카카오 로그인"><svg viewBox="0 0 24 24" aria-hidden="true"><path d="M12 4C6.49 4 2 7.54 2 11.9c0 2.83 1.9 5.3 4.75 6.7l-.82 3.02c-.12.45.38.82.77.56l3.58-2.38c.56.07 1.13.1 1.72.1 5.51 0 10-3.54 10-7.9S17.51 4 12 4Z"/></svg></button></div></main><script type="module">import{createClient}from'https://cdn.jsdelivr.net/npm/@supabase/supabase-js/+esm';const supabase=createClient('https://adltmckypuqwzbcuvuuh.supabase.co','sb_publishable_ZDEvoNTASICy-Z2hqqTOGA_EHFz2Yv1');const checkoutUrl='/order/orderform.html?basket_type=A0000&delvtype=A';const params=new URLSearchParams(location.search);const returnUrl=params.get('returnUrl')||checkoutUrl;const socialPath=name=>'/api/auth/'+name+'?returnUrl='+encodeURIComponent(returnUrl);const form=document.querySelector('.login-form'),emailInput=form?.querySelector('[name="email"]'),passwordInput=form?.querySelector('[name="password"]');document.querySelector('.guest-buy')?.addEventListener('click',()=>{location.href=returnUrl});form?.addEventListener('submit',async event=>{event.preventDefault();const email=emailInput?.value.trim(),password=passwordInput?.value;if(!email||!password){alert('이메일과 비밀번호를 입력해주세요.');return}const{error}=await supabase.auth.signInWithPassword({email,password});if(error){alert(error.message);return}location.href=returnUrl});document.querySelectorAll('.soft-action').forEach(btn=>btn.addEventListener('click',()=>{if(btn.textContent.trim()==='회원가입'){location.href='/member/signup.html?returnUrl='+encodeURIComponent(returnUrl);return}alert('아이디/비밀번호 찾기는 준비 중입니다.')}));document.querySelector('.naver')?.addEventListener('click',()=>{location.href=socialPath('naver')});document.querySelector('.kakao')?.addEventListener('click',()=>{location.href=socialPath('kakao')});</script></body></html>`}
