function signupPage(){return `<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>SIGN UP | BARE.</title><style>@font-face{font-family:InterDisplay;src:url(https://framerusercontent.com/assets/qITWJ2WdG0wrgQPDb8lvnYnTXDg.woff2) format('woff2');font-weight:700;font-display:swap}*{box-sizing:border-box}body{margin:0;background:#fff;color:#111;font-family:InterDisplay,"Apple SD Gothic Neo",Pretendard,"Noto Sans KR",system-ui,sans-serif}.signup-shell{width:min(1560px,calc(100% - 52px));margin:0 auto;padding:34px 0 72px}.signup-top{display:flex;align-items:center;justify-content:space-between;margin-bottom:38px}.signup-logo img{width:74px;filter:brightness(0)}.login-link{color:#111;text-decoration:none;font:900 13px/1 InterDisplay,Pretendard,sans-serif}.signup-grid{display:grid;grid-template-columns:minmax(420px,620px) minmax(420px,1fr);gap:min(10vw,150px);align-items:start}.section-title{margin:0 0 24px;font:900 16px/1.2 Pretendard,"Noto Sans KR",sans-serif}.form-section+.form-section{margin-top:32px}.field-row{display:grid;grid-template-columns:130px minmax(0,1fr);gap:26px;align-items:start;min-height:44px;margin-bottom:20px}.field-label{padding-top:9px;font:900 13px/1.2 Pretendard,"Noto Sans KR",sans-serif}.required{color:#1473ff}.field-control{display:grid;gap:8px}.field-control input,.field-control select{width:100%;height:36px;border:0;border-bottom:2px solid #202020;background:#fff;color:#111;padding:0 4px;font:800 14px/1 Pretendard,"Noto Sans KR",sans-serif}.field-control input::placeholder{color:#aaa}.inline{display:flex;align-items:center;gap:10px;flex-wrap:wrap}.inline input{width:120px}.inline select{width:86px}.address-line{display:grid;grid-template-columns:112px 86px;gap:8px}.address-line button,.verify-btn,.expand-btn{height:34px;border:1px solid #222;background:#fff;color:#111;font:900 12px/1 Pretendard,sans-serif;cursor:pointer}.full-line{width:100%!important}.hint{color:#333;font:800 11px/1.4 Pretendard,"Noto Sans KR",sans-serif}.radio-row,.check-row{display:flex;align-items:center;gap:14px;min-height:34px;font:800 13px/1.4 Pretendard,"Noto Sans KR",sans-serif}.radio-row input,.check-row input{accent-color:#2f7dff}.birth-row{display:flex;align-items:center;gap:8px;flex-wrap:wrap}.birth-row input{width:82px}.birth-row span{font-weight:900}.birth-kind{margin-left:8px}.agreement-head{display:flex;align-items:center;justify-content:space-between;margin-bottom:26px}.all-agree{font:900 13px/1.4 Pretendard,"Noto Sans KR",sans-serif}.agreement-box{border-top:1px solid #bdbdbd;padding:18px 0 24px}.agreement-title{display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;font:900 14px/1.4 Pretendard,"Noto Sans KR",sans-serif}.agreement-options{display:grid;gap:8px;color:#333;font:800 12px/1.5 Pretendard,"Noto Sans KR",sans-serif}.submit-wrap{display:grid;place-items:center;margin-top:72px}.signup-submit{width:150px;height:48px;border:0;background:#eee;color:#111;font:900 14px/1 Pretendard,"Noto Sans KR",sans-serif;cursor:pointer}.signup-submit:disabled{opacity:.55;cursor:wait}.status{min-height:20px;margin:18px 0 0;color:#555;text-align:center;font:800 13px/1.5 Pretendard,"Noto Sans KR",sans-serif}@media(max-width:980px){.signup-shell{width:min(720px,calc(100% - 34px));padding-top:24px}.signup-grid{grid-template-columns:1fr;gap:44px}.field-row{grid-template-columns:104px minmax(0,1fr);gap:16px}.agreement-head{display:grid;gap:12px}}@media(max-width:560px){.signup-shell{width:calc(100% - 28px)}.field-row{grid-template-columns:1fr;gap:8px;margin-bottom:18px}.field-label{padding-top:0}.inline input{width:calc(50% - 8px)}.birth-row input{width:72px}.signup-submit{width:100%}}</style></head><body><main class="signup-shell"><header class="signup-top"><a class="signup-logo" href="/" aria-label="BARE. home"><img src="${logoUrl}" alt="BARE."></a><a class="login-link" href="/member/login.html">LOGIN</a></header><form class="signup-form" id="signup-form"><div class="signup-grid"><section><div class="form-section"><h1 class="section-title">회원구분 <span class="required">*</span></h1><div class="field-row"><div></div><div class="radio-row"><label><input type="radio" name="memberType" value="personal" checked> 개인회원</label><label><input type="radio" name="memberType" value="business"> 사업자회원</label></div></div></div><div class="form-section"><h2 class="section-title">기본정보</h2><div class="field-row"><label class="field-label" for="email">아이디 <span class="required">*</span></label><div class="field-control"><input id="email" name="email" type="email" autocomplete="email" required><p class="hint">로그인에 사용할 이메일 주소를 입력해주세요.</p></div></div><div class="field-row"><label class="field-label" for="password">비밀번호 <span class="required">*</span></label><div class="field-control"><input id="password" name="password" type="password" autocomplete="new-password" minlength="6" required><p class="hint">영문/숫자 조합 6자 이상을 권장합니다.</p></div></div><div class="field-row"><label class="field-label" for="passwordConfirm">비밀번호 확인 <span class="required">*</span></label><div class="field-control"><input id="passwordConfirm" name="passwordConfirm" type="password" autocomplete="new-password" minlength="6" required></div></div><div class="field-row"><label class="field-label" for="name">이름 <span class="required">*</span></label><div class="field-control"><input id="name" name="name" autocomplete="name" required></div></div><div class="field-row"><label class="field-label">주소 <span class="required">*</span></label><div class="field-control"><div class="address-line"><input id="postcode" name="postcode" placeholder="우편번호"><button type="button" id="address-search">주소검색</button></div><input class="full-line" id="address1" name="address1" placeholder="기본주소" required><input class="full-line" id="address2" name="address2" placeholder="나머지 주소(선택 입력 가능)"></div></div><div class="field-row"><label class="field-label">일반전화</label><div class="field-control"><div class="inline"><select name="tel1"><option>02</option><option>031</option><option>032</option><option>051</option><option>053</option><option>직접입력</option></select><span>-</span><input name="tel2" inputmode="numeric"><span>-</span><input name="tel3" inputmode="numeric"></div></div></div><div class="field-row"><label class="field-label">휴대전화 <span class="required">*</span></label><div class="field-control"><div class="inline"><select name="phone1"><option>010</option><option>011</option><option>016</option><option>017</option><option>019</option></select><span>-</span><input name="phone2" inputmode="numeric" required><span>-</span><input name="phone3" inputmode="numeric" required><button class="verify-btn" type="button">인증번호받기</button></div></div></div><div class="field-row"><label class="field-label" for="contactEmail">이메일 <span class="required">*</span></label><div class="field-control"><input id="contactEmail" name="contactEmail" type="email" autocomplete="email" required></div></div></div><div class="form-section"><h2 class="section-title">추가정보</h2><div class="field-row"><span class="field-label">성별</span><div class="radio-row"><label><input type="radio" name="gender" value="male"> 남자</label><label><input type="radio" name="gender" value="female"> 여자</label></div></div><div class="field-row"><span class="field-label">생년월일</span><div class="field-control"><div class="birth-row"><input name="birthYear" inputmode="numeric"><span>년</span><input name="birthMonth" inputmode="numeric"><span>월</span><input name="birthDay" inputmode="numeric"><span>일</span><label class="birth-kind"><input type="radio" name="birthType" value="solar" checked> 양력</label><label><input type="radio" name="birthType" value="lunar"> 음력</label></div></div></div><div class="field-row"><label class="field-label" for="region">지역</label><div class="field-control"><select id="region" name="region"><option value="">선택</option><option>서울</option><option>경기</option><option>인천</option><option>부산</option><option>대구</option><option>광주</option><option>대전</option><option>울산</option><option>세종</option><option>강원</option><option>충북</option><option>충남</option><option>전북</option><option>전남</option><option>경북</option><option>경남</option><option>제주</option></select></div></div></div></section><section><div class="agreement-head"><h2 class="section-title">전체 동의</h2><label class="all-agree"><input type="checkbox" id="agreeAll"> 이용약관 및 개인정보수집 및 이용, 쇼핑정보 수신(선택)에 모두 동의합니다.</label></div><div class="agreement-box"><div class="agreement-title"><span>[필수] 이용약관 동의</span><button class="expand-btn" type="button">펼침</button></div><label class="check-row">이용약관에 동의하십니까? <input type="checkbox" name="terms" required> 동의함</label></div><div class="agreement-box"><div class="agreement-title"><span>[필수] 개인정보 수집 및 이용 동의</span><button class="expand-btn" type="button">펼침</button></div><label class="check-row">개인정보 수집 및 이용에 동의하십니까? <input type="checkbox" name="privacy" required> 동의함</label></div><div class="agreement-box"><div class="agreement-title"><span>[선택] 쇼핑정보 수신 동의</span><button class="expand-btn" type="button">펼침</button></div><div class="agreement-options"><label>SMS 수신을 동의하십니까? <input type="checkbox" name="smsMarketing"> 동의함</label><label>이메일 수신을 동의하십니까? <input type="checkbox" name="emailMarketing"> 동의함</label></div></div><div class="submit-wrap"><button class="signup-submit" type="submit">회원가입</button><p class="status" id="signup-status"></p></div></section></div></form></main><script type="module">import{createClient}from'https://cdn.jsdelivr.net/npm/@supabase/supabase-js/+esm';const supabase=createClient('https://adltmckypuqwzbcuvuuh.supabase.co','sb_publishable_ZDEvoNTASICy-Z2hqqTOGA_EHFz2Yv1');const form=document.getElementById('signup-form'),statusEl=document.getElementById('signup-status'),submit=form.querySelector('.signup-submit'),email=document.getElementById('email'),contactEmail=document.getElementById('contactEmail');function setStatus(text){statusEl.textContent=text}email.addEventListener('input',()=>{if(!contactEmail.value)contactEmail.value=email.value});document.getElementById('agreeAll').addEventListener('change',event=>{form.querySelectorAll('input[type="checkbox"]').forEach(input=>{input.checked=event.target.checked})});document.getElementById('address-search').addEventListener('click',()=>alert('주소 검색 API 연동 전입니다. 주소를 직접 입력해주세요.'));form.querySelectorAll('.expand-btn').forEach(btn=>btn.addEventListener('click',()=>alert('약관 상세 내용은 약관 페이지에서 확인할 수 있도록 연결 예정입니다.')));form.addEventListener('submit',async event=>{event.preventDefault();if(!form.reportValidity())return;const fd=new FormData(form);const password=String(fd.get('password')||''),passwordConfirm=String(fd.get('passwordConfirm')||'');if(password!==passwordConfirm){setStatus('비밀번호 확인이 일치하지 않습니다.');return}const phone=[fd.get('phone1'),fd.get('phone2'),fd.get('phone3')].filter(Boolean).join('-');const tel=[fd.get('tel1'),fd.get('tel2'),fd.get('tel3')].filter(Boolean).join('-');const address=[fd.get('postcode'),fd.get('address1'),fd.get('address2')].filter(Boolean).join(' ');const metadata={member_type:fd.get('memberType'),name:fd.get('name'),phone,tel,address,postcode:fd.get('postcode')||'',contact_email:fd.get('contactEmail'),gender:fd.get('gender')||'',birth:[fd.get('birthYear'),fd.get('birthMonth'),fd.get('birthDay')].filter(Boolean).join('-'),birth_type:fd.get('birthType')||'',region:fd.get('region')||'',marketing_sms:fd.has('smsMarketing'),marketing_email:fd.has('emailMarketing')};submit.disabled=true;setStatus('회원가입을 처리하고 있습니다.');const{data,error}=await supabase.auth.signUp({email:String(fd.get('email')||'').trim(),password,options:{data:metadata,emailRedirectTo:location.origin+'/member/login.html'}});submit.disabled=false;if(error){setStatus(error.message);return}setStatus(data.session?'회원가입이 완료됐어요. 로그인 상태로 이동합니다.':'가입 메일을 보냈어요. 이메일 인증 후 로그인해주세요.');setTimeout(()=>{location.href='/member/login.html'},data.session?900:1600)});</script></body></html>`}
function socialMessagePage(title,message,returnUrl='/member/login.html'){return new Response(`<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>${title} | BARE.</title><style>body{margin:0;display:grid;place-items:center;min-height:100svh;background:#fff;color:#202020;font-family:Arial,"Apple SD Gothic Neo",sans-serif}.box{width:min(420px,calc(100% - 36px));text-align:center}.box h1{font-size:24px}.box p{font-size:15px;line-height:1.6;color:#666}.box a{display:inline-flex;align-items:center;justify-content:center;height:46px;padding:0 18px;margin-top:18px;background:#202020;color:#fff;text-decoration:none;font-weight:900}</style></head><body><main class="box"><h1>${title}</h1><p>${message}</p><a href="${returnUrl}">돌아가기</a></main></body></html>`,{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}})}
function redirect(location){return new Response(null,{status:302,headers:{location,'cache-control':'no-cache'}})}
function socialCompletePage(provider,user,returnUrl){const payload=JSON.stringify({provider,name:user.name||'',email:user.email||'',id:user.id||'',createdAt:Date.now()}).replace(/</g,'\\u003c');return new Response(`<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>LOGIN COMPLETE | BARE.</title></head><body><script>localStorage.setItem('bare_social_user',${JSON.stringify(payload)});location.replace(${JSON.stringify(returnUrl)});</script></body></html>`,{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}})}
async function startSocialAuth(request,env,provider){const url=new URL(request.url),origin=url.origin,returnUrl=safeReturnUrl(url.searchParams.get('returnUrl'));if(provider==='kakao'){const clientId=env.KAKAO_REST_API_KEY||env.KAKAO_CLIENT_ID;if(!clientId)return socialMessagePage('카카오 키가 필요해요','Cloudflare Pages 환경변수에 KAKAO_REST_API_KEY를 추가하면 카카오 로그인이 바로 열립니다.','/member/login.html?returnUrl='+encodeURIComponent(returnUrl));const redirectUri=origin+'/api/auth/kakao/callback';const auth=new URL('https://kauth.kakao.com/oauth/authorize');auth.searchParams.set('response_type','code');auth.searchParams.set('client_id',clientId);auth.searchParams.set('redirect_uri',redirectUri);auth.searchParams.set('state',encodeState({returnUrl}));return redirect(auth.toString())}const clientId=env.NAVER_CLIENT_ID;if(!clientId)return socialMessagePage('네이버 키가 필요해요','Cloudflare Pages 환경변수에 NAVER_CLIENT_ID와 NAVER_CLIENT_SECRET을 추가하면 네이버 로그인이 바로 열립니다.','/member/login.html?returnUrl='+encodeURIComponent(returnUrl));const auth=new URL('https://nid.naver.com/oauth2.0/authorize');auth.searchParams.set('response_type','code');auth.searchParams.set('client_id',clientId);auth.searchParams.set('redirect_uri',origin+'/api/auth/naver/callback');auth.searchParams.set('state',encodeState({returnUrl}));return redirect(auth.toString())}
async function handleSocialCallback(request,env,provider){const url=new URL(request.url),code=url.searchParams.get('code'),state=url.searchParams.get('state'),data=decodeState(state),returnUrl=safeReturnUrl(data.returnUrl);if(!code)return socialMessagePage('로그인 실패','간편 로그인 승인 코드가 없습니다.','/member/login.html?returnUrl='+encodeURIComponent(returnUrl));try{if(provider==='kakao'){const clientId=env.KAKAO_REST_API_KEY||env.KAKAO_CLIENT_ID;if(!clientId)throw new Error('KAKAO_REST_API_KEY가 없습니다.');const body=new URLSearchParams({grant_type:'authorization_code',client_id:clientId,redirect_uri:url.origin+'/api/auth/kakao/callback',code});if(env.KAKAO_CLIENT_SECRET)body.set('client_secret',env.KAKAO_CLIENT_SECRET);const tokenRes=await fetch('https://kauth.kakao.com/oauth/token',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded;charset=utf-8'},body});const token=await tokenRes.json();if(!tokenRes.ok)throw new Error(token.error_description||'카카오 토큰 발급 실패');const profileRes=await fetch('https://kapi.kakao.com/v2/user/me',{headers:{Authorization:'Bearer '+token.access_token}});const profile=await profileRes.json();if(!profileRes.ok)throw new Error('카카오 프로필 조회 실패');const account=profile.kakao_account||{},kakaoProfile=account.profile||{};return socialCompletePage('kakao',{id:String(profile.id||''),email:account.email||'',name:kakaoProfile.nickname||'Kakao User'},returnUrl)}const clientId=env.NAVER_CLIENT_ID,clientSecret=env.NAVER_CLIENT_SECRET;if(!clientId||!clientSecret)throw new Error('NAVER_CLIENT_ID 또는 NAVER_CLIENT_SECRET이 없습니다.');const tokenUrl=new URL('https://nid.naver.com/oauth2.0/token');tokenUrl.searchParams.set('grant_type','authorization_code');tokenUrl.searchParams.set('client_id',clientId);tokenUrl.searchParams.set('client_secret',clientSecret);tokenUrl.searchParams.set('code',code);tokenUrl.searchParams.set('state',state||'');const tokenRes=await fetch(tokenUrl.toString());const token=await tokenRes.json();if(!tokenRes.ok||!token.access_token)throw new Error(token.error_description||'네이버 토큰 발급 실패');const profileRes=await fetch('https://openapi.naver.com/v1/nid/me',{headers:{Authorization:'Bearer '+token.access_token}});const profile=await profileRes.json();if(!profileRes.ok||profile.resultcode!=='00')throw new Error('네이버 프로필 조회 실패');const user=profile.response||{};return socialCompletePage('naver',{id:user.id||'',email:user.email||'',name:user.name||user.nickname||'Naver User'},returnUrl)}catch(error){return socialMessagePage('로그인 실패',error.message||'간편 로그인 처리 중 문제가 생겼습니다.','/member/login.html?returnUrl='+encodeURIComponent(returnUrl))}}
