function otpResponse(data,status=200){return new Response(JSON.stringify(data),{status,headers:{'content-type':'application/json;charset=utf-8','cache-control':'no-store'}})}
function normalizePhone(value){return String(value||'').replace(/[^0-9]/g,'')}
function randomHex(bytes=16){const value=new Uint8Array(bytes);crypto.getRandomValues(value);return [...value].map(item=>item.toString(16).padStart(2,'0')).join('')}
async function hmacHex(secret,value){const encoder=new TextEncoder(),key=await crypto.subtle.importKey('raw',encoder.encode(secret),{name:'HMAC',hash:'SHA-256'},false,['sign']),signature=await crypto.subtle.sign('HMAC',key,encoder.encode(value));return [...new Uint8Array(signature)].map(item=>item.toString(16).padStart(2,'0')).join('')}
function timingSafeEqual(left,right){if(typeof left!=='string'||typeof right!=='string'||left.length!==right.length)return false;let different=0;for(let index=0;index<left.length;index++)different|=left.charCodeAt(index)^right.charCodeAt(index);return different===0}
function otpEnvironmentReady(env){return env.OTP_STORE&&env.SOLAPI_API_KEY&&env.SOLAPI_API_SECRET&&env.SOLAPI_SENDER&&env.OTP_HASH_SECRET}
async function readOtpBody(request){try{return await request.json()}catch{return null}}
function sameOriginRequest(request){const origin=request.headers.get('origin');return !origin||origin===new URL(request.url).origin}
async function sendPhoneOtp(request,env){
  if(request.method!=='POST')return otpResponse({message:'허용되지 않은 요청입니다.'},405);
  if(!sameOriginRequest(request))return otpResponse({message:'잘못된 요청입니다.'},403);
  if(!otpEnvironmentReady(env))return otpResponse({message:'휴대전화 인증 설정이 완료되지 않았습니다.'},503);
  const body=await readOtpBody(request),phone=normalizePhone(body?.phone);
  if(!/^010\d{8}$/.test(phone))return otpResponse({message:'010으로 시작하는 휴대전화번호를 확인해주세요.'},400);
  const ip=request.headers.get('cf-connecting-ip')||'unknown',ipKey=await hmacHex(env.OTP_HASH_SECRET,ip),cooldownKey='otp:cooldown:'+phone,phoneDailyKey='otp:daily:phone:'+phone,ipDailyKey='otp:daily:ip:'+ipKey;
  if(await env.OTP_STORE.get(cooldownKey))return otpResponse({message:'인증번호는 60초 후 다시 받을 수 있습니다.',retryAfter:60},429);
  const phoneDaily=Number(await env.OTP_STORE.get(phoneDailyKey)||0),ipDaily=Number(await env.OTP_STORE.get(ipDailyKey)||0);
  if(phoneDaily>=5||ipDaily>=20)return otpResponse({message:'오늘 인증번호 발송 한도를 초과했습니다. 내일 다시 시도해주세요.'},429);
  const values=new Uint32Array(1);crypto.getRandomValues(values);const code=String(values[0]%1000000).padStart(6,'0'),expiresAt=Date.now()+5*60*1000,codeHash=await hmacHex(env.OTP_HASH_SECRET,phone+':'+code+':'+expiresAt),date=new Date().toISOString(),salt=randomHex(),signature=await hmacHex(env.SOLAPI_API_SECRET,date+salt),authorization='HMAC-SHA256 apiKey='+env.SOLAPI_API_KEY+', date='+date+', salt='+salt+', signature='+signature;
  const solapiResponse=await fetch('https://api.solapi.com/messages/v4/send-many/detail',{method:'POST',headers:{Authorization:authorization,'Content-Type':'application/json'},body:JSON.stringify({messages:[{to:phone,from:normalizePhone(env.SOLAPI_SENDER),text:'[BARE.] 인증번호는 '+code+'입니다. 5분 내 입력해주세요.',type:'SMS'}]})});
  let result={};try{result=await solapiResponse.json()}catch{}
  if(!solapiResponse.ok||result.failedMessageList?.length)return otpResponse({message:result.errorMessage||result.failedMessageList?.[0]?.statusMessage||'인증문자를 발송하지 못했습니다.'},502);
  await Promise.all([
    env.OTP_STORE.put('otp:code:'+phone,JSON.stringify({hash:codeHash,expiresAt,attempts:0}),{expirationTtl:300}),
    env.OTP_STORE.put(cooldownKey,'1',{expirationTtl:60}),
    env.OTP_STORE.put(phoneDailyKey,String(phoneDaily+1),{expirationTtl:86400}),
    env.OTP_STORE.put(ipDailyKey,String(ipDaily+1),{expirationTtl:86400})
  ]);
  return otpResponse({ok:true,message:'인증번호를 발송했습니다.',expiresIn:300,retryAfter:60});
}
async function verifyPhoneOtp(request,env){
  if(request.method!=='POST')return otpResponse({message:'허용되지 않은 요청입니다.'},405);
  if(!sameOriginRequest(request))return otpResponse({message:'잘못된 요청입니다.'},403);
  if(!otpEnvironmentReady(env))return otpResponse({message:'휴대전화 인증 설정이 완료되지 않았습니다.'},503);
  const body=await readOtpBody(request),phone=normalizePhone(body?.phone),code=String(body?.code||'').replace(/[^0-9]/g,'');
  if(!/^010\d{8}$/.test(phone)||!/^\d{6}$/.test(code))return otpResponse({message:'휴대전화번호와 6자리 인증번호를 확인해주세요.'},400);
  const key='otp:code:'+phone,stored=await env.OTP_STORE.get(key,'json');
  if(!stored||Date.now()>Number(stored.expiresAt)){await env.OTP_STORE.delete(key);return otpResponse({message:'인증번호가 만료됐습니다. 다시 받아주세요.'},410)}
  if(Number(stored.attempts||0)>=5){await env.OTP_STORE.delete(key);return otpResponse({message:'인증번호 입력 횟수를 초과했습니다. 다시 받아주세요.'},429)}
  const expected=await hmacHex(env.OTP_HASH_SECRET,phone+':'+code+':'+stored.expiresAt);
  if(!timingSafeEqual(expected,stored.hash)){stored.attempts=Number(stored.attempts||0)+1;await env.OTP_STORE.put(key,JSON.stringify(stored),{expirationTtl:Math.max(60,Math.ceil((stored.expiresAt-Date.now())/1000))});return otpResponse({message:'인증번호가 일치하지 않습니다.',attemptsLeft:Math.max(0,5-stored.attempts)},400)}
  await env.OTP_STORE.delete(key);return otpResponse({ok:true,message:'휴대전화 인증이 완료됐습니다.',phone});
}

const otpSignupStyle='<style id="bare-phone-otp-style">.phone-otp{display:none;flex:1 0 100%;align-items:center;gap:8px;margin-top:4px}.phone-otp.is-open{display:flex}.phone-otp input{width:138px!important}.phone-otp button{height:34px;border:1px solid #222;background:#111;color:#fff;padding:0 12px;font:900 11px/1 Pretendard,sans-serif;cursor:pointer}.phone-status{flex:1 0 100%;min-height:16px;margin:0;color:#555;font:800 11px/1.4 Pretendard,sans-serif}.phone-status.is-success{color:#1473ff}.verify-btn:disabled,.phone-otp button:disabled{opacity:.55;cursor:wait}@media(max-width:560px){.phone-otp input{width:min(160px,55%)!important}.phone-otp button{flex:1}}</style>';
