const otpSignupScript=`<script id="bare-phone-otp-script">(()=>{const form=document.getElementById('signup-form'),sendButton=form?.querySelector('.verify-btn'),phoneInputs=[form?.querySelector('[name="phone1"]'),form?.querySelector('[name="phone2"]'),form?.querySelector('[name="phone3"]')].filter(Boolean),box=document.getElementById('phone-otp'),codeInput=document.getElementById('phone-otp-code'),confirmButton=document.getElementById('phone-otp-confirm'),status=document.getElementById('phone-status');if(!form||!sendButton||!box||!codeInput||!confirmButton||!status)return;let verifiedPhone='';const phone=()=>phoneInputs.map(input=>input.value).join('').replace(/[^0-9]/g,'');const setStatus=(text,success=false)=>{status.textContent=text;status.classList.toggle('is-success',success)};const reset=()=>{verifiedPhone='';setStatus('');codeInput.value=''};phoneInputs.forEach(input=>input.addEventListener('input',reset));sendButton.addEventListener('click',async()=>{const value=phone();if(!/^010\\d{8}$/.test(value)){setStatus('휴대전화번호를 정확히 입력해주세요.');return}reset();sendButton.disabled=true;setStatus('인증번호를 발송하고 있습니다.');try{const response=await fetch('/api/phone/send',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({phone:value})}),data=await response.json();if(!response.ok)throw new Error(data.message||'인증번호를 발송하지 못했습니다.');box.classList.add('is-open');codeInput.focus();setStatus('인증번호를 발송했습니다. 5분 안에 입력해주세요.');setTimeout(()=>{if(!verifiedPhone)sendButton.disabled=false},60000)}catch(error){sendButton.disabled=false;setStatus(error.message)}});confirmButton.addEventListener('click',async()=>{const value=phone(),code=codeInput.value.replace(/[^0-9]/g,'');if(!/^\\d{6}$/.test(code)){setStatus('6자리 인증번호를 입력해주세요.');return}confirmButton.disabled=true;setStatus('인증번호를 확인하고 있습니다.');try{const response=await fetch('/api/phone/verify',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({phone:value,code})}),data=await response.json();if(!response.ok)throw new Error(data.message||'인증번호를 확인하지 못했습니다.');verifiedPhone=value;phoneInputs.forEach(input=>input.readOnly=true);sendButton.disabled=true;box.classList.remove('is-open');setStatus('휴대전화 인증이 완료됐습니다.',true)}catch(error){setStatus(error.message)}finally{confirmButton.disabled=false}});form.addEventListener('submit',event=>{if(verifiedPhone!==phone()){event.preventDefault();event.stopImmediatePropagation();setStatus('휴대전화 인증을 완료해주세요.');sendButton.focus()}},true)})();</script>`;
